from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_mail import Mail
import string
import secrets

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////tmp/test.db'
app.config['MAIL_SERVER'] = 'smtp.googlemail.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = 'your_email@gmail.com'
app.config['MAIL_PASSWORD'] = 'your_password'
mail = Mail(app)
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(80), unique=True, nullable=False)
    reset_token = db.Column(db.String(120))

def generate_reset_link():
    return ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(64))

@app.route('/api/password-reset', methods=['POST'])
def password_reset():
    email = request.json.get('email')
    user = User.query.filter_by(email=email).first()

    if not user:
        return jsonify({'error': 'User not found'}), 404

    reset_token = generate_reset_link()
    user.reset_token = reset_token
    db.session.commit()

    msg = MailMessage('Password Reset Request', email, sender='noreply@example.com')
    msg.html = f'<p>Your password reset link: <a href="http://localhost/api/password-reset/{user.reset_token}">Reset Password</a></p>'
    mail.send(msg)

    return jsonify({'message': 'Password reset link sent to your email'})

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)